import axios from 'axios';

async function cekPaket(phoneNumber) {
    try {
        const cleanNumber = phoneNumber.replace(/\D/g, '');
        const number = cleanNumber.startsWith('628') ? '0' + cleanNumber.slice(2) : cleanNumber;

        const { data } = await axios.get('https://xl-ku.my.id/end.php', {
            params: {
                check: 'package',
                number: number,
                version: '2'
            },
            timeout: 10000
        });

        if (!data.success) {
            return {
                success: false,
                message: data.message || 'Gagal cek paket'
            };
        }

        const info = data.data.subs_info;
        const packages = data.data.package_info.packages;

        const result = {
            success: true,
            number: info.msisdn,
            operator: info.operator,
            network: info.net_type,
            activePeriod: info.tenure,
            expired: info.exp_date,
            graceUntil: info.grace_until,
            volte: info.volte,
            packages: packages.map(pkg => ({
                name: pkg.name,
                expired: pkg.expiry,
                quotas: pkg.quotas
                    .filter(q => parseFloat(q.remaining) > 0 || q.remaining.includes('Menit'))
                    .map(q => ({
                        name: q.name,
                        total: q.total,
                        remaining: q.remaining,
                        percent: q.percent.toFixed(1) + '%'
                    }))
            }))
        };

        console.log(JSON.stringify(result, null, 2));
        return result;

    } catch (error) {
        const errorResult = {
            success: false,
            message: error.message
        };
        console.log(JSON.stringify(errorResult, null, 2));
        return errorResult;
    }
}

