async function getCharacter(slug) {
    try {
        const { data } = await axios.get(`https://en-portal.g.kuroco.app/rcms-api/4/characters/${slug}`, {
            timeout: 10000
        });

        const char = data.details;

        const result = {
            success: true,
            name: char.subject,
            slug: char.slug,
            color: char.color,
            profile: {
                catch: char.profile.catch || null,
                va: char.profile.va || null,
                birthday: char.profile.birthday || null,
                height: char.profile.height || null,
                weight: char.profile.weight || null,
                detail: char.profile.detail || null
            },
            voice: char.voice || null,
            images: {
                icon: char.download?.icon || null,
                banner: char.download?.banner || null,
                gallery: Array.isArray(char.visual)
                    ? char.visual.map(v => ({
                        label: v.name.label,
                        image: v.image,
                        thumb: v.thumb
                    }))
                    : char.visual
                        ? [{ label: 'Visual', image: char.visual, thumb: null }]
                        : []
            }
        };

        Object.keys(result.profile).forEach(key => {
            if (result.profile[key] === null) delete result.profile[key];
        });

        if (result.images.gallery.length === 0) delete result.images.gallery;

        return result;

    } catch (error) {
        return {
            success: false,
            message: error.message
        };
    }
}

async function searchCharacter(query) {
    try {
        const { data } = await axios.get('https://en-portal.g.kuroco.app/rcms-api/4/characters', {
            timeout: 10000
        });

        const searchLower = query.toLowerCase();
        const allChars = [...data.umamusume, ...data.other];

        const found = allChars.find(char =>
            char.subject.toLowerCase().includes(searchLower)
        );

        if (!found) {
            return {
                success: false,
                message: `Karakter "${query}" tidak ditemukan`
            };
        }

        return await getCharacter(found.slug);

    } catch (error) {
        return {
            success: false,
            message: error.message
        };
    }
}

