import sys
import requests
import json


BASE_URL = "https://en-portal.g.kuroco.app/rcms-api/4/characters"
TIMEOUT = 10


def get_character(slug):
    try:
        response = requests.get(
            f"{BASE_URL}/{slug}",
            timeout=TIMEOUT
        )
        response.raise_for_status()
        data = response.json()
        char = data["details"]

        result = {
            "success": True,
            "name": char["subject"],
            "slug": char["slug"],
            "color": char.get("color"),
            "profile": {},
            "voice": char.get("voice"),
            "images": {}
        }

        profile = char.get("profile", {})
        profile_fields = {
            "catch": profile.get("catch"),
            "va": profile.get("va"),
            "birthday": profile.get("birthday"),
            "height": profile.get("height"),
            "weight": profile.get("weight"),
            "detail": profile.get("detail")
        }

        for key, value in profile_fields.items():
            if value is not None:
                result["profile"][key] = value

        if not result["profile"]:
            del result["profile"]

        download = char.get("download", {})
        result["images"]["icon"] = download.get("icon")
        result["images"]["banner"] = download.get("banner")

        visual = char.get("visual")
        if visual:
            if isinstance(visual, list):
                gallery = []
                for v in visual:
                    gallery.append({
                        "label": v["name"]["label"],
                        "image": v["image"],
                        "thumb": v.get("thumb")
                    })
                result["images"]["gallery"] = gallery
            elif isinstance(visual, dict):
                result["images"]["gallery"] = [{
                    "label": "Visual",
                    "image": visual["image"],
                    "thumb": visual.get("thumb")
                }]

        for key in list(result["images"].keys()):
            if result["images"][key] is None:
                del result["images"][key]
            elif key == "gallery" and len(result["images"]["gallery"]) == 0:
                del result["images"]["gallery"]

        if not result["images"]:
            del result["images"]

        if result.get("voice") is None:
            del result["voice"]

        return result

    except requests.exceptions.RequestException as error:
        return {
            "success": False,
            "message": str(error)
        }
    except (KeyError, TypeError, ValueError) as error:
        return {
            "success": False,
            "message": f"Data parsing error: {str(error)}"
        }


def search_character(query):
    try:
        response = requests.get(BASE_URL, timeout=TIMEOUT)
        response.raise_for_status()
        data = response.json()

        search_lower = query.lower()
        all_chars = data.get("umamusume", []) + data.get("other", [])

        found = None
        for char in all_chars:
            if search_lower in char.get("subject", "").lower():
                found = char
                break

        if not found:
            return {
                "success": False,
                "message": f'Karakter "{query}" tidak ditemukan'
            }

        return get_character(found["slug"])

    except requests.exceptions.RequestException as error:
        return {
            "success": False,
            "message": str(error)
        }
    except (KeyError, TypeError, ValueError) as error:
        return {
            "success": False,
            "message": f"Data parsing error: {str(error)}"
        }


def main():
    query = sys.argv[1] if len(sys.argv) > 1 else "tokaiteio"
    result = search_character(query)
    print(json.dumps(result, indent=2, ensure_ascii=False))


if __name__ == "__main__":
    main()
